sql:
SELECT country_code 
FROM states_provinces 
WHERE state_province_name = 'New York';

SELECT SUM(population) AS total_population 
FROM states_provinces 
WHERE country_code = 'AU';

SELECT manager_id
FROM sales_territories
WHERE revenue = (SELECT MAX(revenue) FROM sales_territories);

external_knowledge:
- UTC+8 refers to a timezone that is eight hours ahead of Coordinated Universal Time; 
- USD stands for United States dollar, the official currency of the United States; 
- EUR stands for European euro, the official currency of the European Union.

sql:
SELECT AVG(population) AS average_population
FROM states_provinces
WHERE country_code = 'AU' AND population > 5000000;

SELECT manager_id, country_code
FROM sales_territories
WHERE revenue > 500000000.0;

SELECT state_province_name, population
  FROM states_provinces
  ORDER BY population DESC;
